            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/dashboard"]""",
            Tags = """["search","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"sr1","text":"You need to find a job fast, but you're on the Expenses page right now. What's the quickest way to start searching?","options":[{"id":"a","text":"Go to the board first, then use the board's own filter"},{"id":"b","text":"Press Ctrl+K to jump to the search box in the header, then type the job number","isCorrect":true},{"id":"c","text":"Go to Reports and run a Job Lookup report"},{"id":"d","text":"Open the sidebar and click a Search menu item"}],"explanation":"Ctrl+K jumps to the search box from any page. You don't have to go anywhere first — just press Ctrl+K and start typing. The search box is always in the header."},{"id":"sr2","text":"How many kinds of things does search look through at once?","options":[{"id":"a","text":"3 — jobs, parts, and customers"},{"id":"b","text":"4 — jobs, customers, parts, and leads"},{"id":"c","text":"6 — jobs, customers, parts, leads, assets, and expenses","isCorrect":true},{"id":"d","text":"Everything stored in the app"}],"explanation":"Search looks through 6 kinds of things at once: jobs, customers, parts, leads, assets, and expenses. Each has its own icon so you can tell them apart."},{"id":"sr3","text":"You type a single letter 'A' into the search box. What happens?","options":[{"id":"a","text":"Results appear showing everything that starts with A"},{"id":"b","text":"Nothing — you need at least 2 letters before search runs","isCorrect":true},{"id":"c","text":"An error message asks you to type more"},{"id":"d","text":"The AI helper suggests things based on the letter"}],"explanation":"Search needs at least 2 letters before it looks anything up. One letter brings back nothing. This keeps searches from being so broad they return everything."},{"id":"sr4","text":"What does each search result show?","options":[{"id":"a","text":"Just the name and a link"},{"id":"b","text":"An icon for the type, a main title, a bit of context underneath, and a type tag","isCorrect":true},{"id":"c","text":"A thumbnail picture, the full description, and the date it was created"},{"id":"d","text":"A record ID, a database table name, and the last-changed time"}],"explanation":"Each result shows four things: an icon telling you the type, the main title (job number, customer name, and so on), a bit of context underneath, and a type tag (Job, Customer, Part, and so on)."},{"id":"sr5","text":"The results show two columns instead of one. What does that mean?","options":[{"id":"a","text":"There are too many results to fit in one column"},{"id":"b","text":"The AI helper is on — plain text matches on the left, AI results on the right","isCorrect":true},{"id":"c","text":"You're searching two different places at once"},{"id":"d","text":"The screen is just wide enough for two columns"}],"explanation":"When the AI helper is on, the results split into two columns. The left shows plain text matches; the right shows AI results, including a written answer and snippets that match the meaning of your question."},{"id":"sr6","text":"An AI result shows a match score of 87%. What does that number mean?","options":[{"id":"a","text":"How many words from your search show up in the document"},{"id":"b","text":"How closely the snippet fits the meaning of your search","isCorrect":true},{"id":"c","text":"How sure it is the document isn't a duplicate"},{"id":"d","text":"How much of the document has been indexed"}],"explanation":"The match score shows how closely a snippet fits the meaning of your search, not just whether the same words appear. A higher score means a closer match."},{"id":"sr7","text":"You search for 'aluminum housing' but no job title or part number has those exact words. How can search still help?","options":[{"id":"a","text":"It can't — search only finds the exact words in certain fields"},{"id":"b","text":"The AI column can find related records even without the exact words, showing matching snippets and a written answer","isCorrect":true},{"id":"c","text":"It automatically switches to a loose spelling mode"},{"id":"d","text":"It reads through every PDF you've uploaded"}],"explanation":"The AI helper finds records by meaning, not just exact words. Even if 'aluminum housing' isn't written anywhere, it can surface records about aluminum machining or housing parts and show related snippets with a written answer."},{"id":"sr8","text":"You click a Part in the search results. What happens next?","options":[{"id":"a","text":"The part's details open right over the Parts list, the box clears, and the results close","isCorrect":true},{"id":"b","text":"You land on the plain Parts list with nothing selected"},{"id":"c","text":"The part's info is copied to your clipboard"},{"id":"d","text":"A new browser tab opens with the part details"}],"explanation":"Clicking a result doesn't just drop you on a list — it opens that record's details right over its list, and the details stay in the web address so you can bookmark or share the link. Jobs, customers, leads, and assets work the same way; expenses are the only exception (they just open the Expenses list)."}]}"""
